export enum AppMode {
  SUBJECT_SELECTION = 'SUBJECT_SELECTION',
  DASHBOARD = 'DASHBOARD',
  MIND_MAP = 'MIND_MAP',
  ACTIVE_RECALL = 'ACTIVE_RECALL',
  FLASHCARDS = 'FLASHCARDS',
  DOUBT_SOLVER = 'DOUBT_SOLVER',
  REVISION = 'REVISION',
  ADMIN = 'ADMIN'
}

export enum Theme {
  LIGHT = 'light',
  DARK = 'dark',
  READING = 'reading'
}

export interface Concept {
  id: string;
  title: string;
  description: string;
  dependencyNote?: string;
  estimatedMinutes: number;
  status: 'LOCKED' | 'NOT_STARTED' | 'IN_PROGRESS' | 'MASTERED';
  masteryLevel: number; // 0-100
  prerequisites: string[];
}

export interface Chapter {
  id: string;
  title: string;
  subject: string;
  concepts: Concept[];
  createdAt?: number;
}

export interface Flashcard {
  id: string;
  front: string;
  back: string;
  mastery: 'AGAIN' | 'HARD' | 'GOOD' | 'EASY';
  nextReviewDate: Date;
  conceptId: string;
  chapterId: string;
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Message, Chapter } from '../types';

// Safely accessing the API key (assumed to be in process.env)
const API_KEY = process.env.API_KEY || '';

let ai: GoogleGenAI | null = null;

export const initGemini = () => {
  if (!API_KEY) {
    console.warn("Gemini API Key is missing.");
    return;
  }
  if (!ai) {
    ai = new GoogleGenAI({ apiKey: API_KEY });
  }
};

export const generateChapter = async (topic: string, level: string): Promise<Chapter | null> => {
  if (!ai) initGemini();
  if (!ai) {
    console.error("AI not initialized");
    return null;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a structured learning path for the topic: "${topic}" at the level of "${level}".
      Structure this as a Chapter with sequential Concepts.

      Rules:
      1. Create 5-8 concepts that build upon each other logically.
      2. 'status' should default to 'NOT_STARTED' (or 'LOCKED' for later ones if you prefer, but 'NOT_STARTED' is fine).
      3. 'dependencyNote' explains WHY the previous concept is needed for this one.
      4. 'estimatedMinutes' should be realistic (10-30 mins).

      Return valid JSON matching the schema.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "The main chapter title" },
            subject: { type: Type.STRING, description: "The broader subject (e.g. Physics, History)" },
            concepts: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  dependencyNote: { type: Type.STRING },
                  estimatedMinutes: { type: Type.INTEGER },
                  prerequisites: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["title", "description", "estimatedMinutes"]
              }
            }
          },
          required: ["title", "subject", "concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || "{}");

    // Post-process to add IDs and ensure structure match
    const chapterId = `chap_${Date.now()}`;
    const concepts = (data.concepts || []).map((c: any, index: number) => ({
      ...c,
      id: `${chapterId}_c${index + 1}`,
      status: index === 0 ? 'NOT_STARTED' : 'LOCKED', // Lock all except first
      masteryLevel: 0,
      prerequisites: index > 0 ? [`${chapterId}_c${index}`] : [], // Simple linear dependency for generated content
      dependencyNote: c.dependencyNote || (index > 0 ? "Building on previous concept" : "Foundational")
    }));

    return {
      id: chapterId,
      title: data.title || topic,
      subject: data.subject || "General",
      concepts: concepts,
      createdAt: Date.now()
    };

  } catch (error) {
    console.error("Generate Chapter Error:", error);
    return null;
  }
};

export const generateRecallQuestion = async (conceptTitle: string, context: string): Promise<string> => {
  if (!ai) initGemini();
  if (!ai) return "Describe the main idea of this concept.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a single, conceptual active recall question for the concept "${conceptTitle}".
      Context of chapter: ${context}.
      The question should NOT be multiple choice. It should require explanation or reasoning.
      Keep it short (under 20 words).`,
    });
    return response.text?.trim() || "Explain this concept in your own words.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Explain the core principle of this concept.";
  }
};

export const evaluateAnswer = async (question: string, userAnswer: string, conceptTitle: string): Promise<{ isCorrect: boolean; feedback: string }> => {
  if (!ai) initGemini();
  if (!ai) return { isCorrect: true, feedback: "Simulation: Good job!" };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a strict but helpful tutor.
      Concept: ${conceptTitle}
      Question: ${question}
      Student Answer: ${userAnswer}

      Evaluate the answer based on conceptual understanding, not just keyword matching.
      Return a JSON object with:
      1. isCorrect (boolean): true if the student understands the core concept, false otherwise.
      2. feedback (string): A brief, constructive explanation (max 2 sentences).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            feedback: { type: Type.STRING },
          },
          required: ["isCorrect", "feedback"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response text");
    return JSON.parse(text);

  } catch (error) {
    console.error("Evaluation Error:", error);
    return { isCorrect: false, feedback: "Could not evaluate answer due to connection error. Please try again." };
  }
};

export const getDoubtResponse = async (history: Message[], currentContext: string): Promise<string> => {
  if (!ai) initGemini();
  if (!ai) return "I am ready to help, but the AI service is currently unavailable.";

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are an expert Tutor.
        The student is studying: ${currentContext}.
        Answer their doubts with clarity, using analogies.
        Prioritize logic over rote memorization.
        Be concise.`,
      },
    });

    const lastUserMessage = history[history.length - 1];

    const result = await chat.sendMessage({
      message: lastUserMessage.content
    });

    return result.text || "I'm not sure how to answer that right now.";

  } catch (error) {
    console.error("Doubt Solver Error:", error);
    return "I encountered an error trying to process your doubt.";
  }
};

import React, { useState } from 'react';
