import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ChapterBreakdown from './components/ChapterBreakdown';
import MindMap from './components/MindMap';
import ActiveRecall from './components/ActiveRecall';
import Flashcards from './components/Flashcards';
import DoubtSolver from './components/DoubtSolver';
import RevisionMode from './components/RevisionMode';
import AdminDashboard from './components/AdminDashboard';
import SubjectSelection from './components/SubjectSelection';
import { AppMode, Theme, Chapter, Flashcard } from './types';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.SUBJECT_SELECTION);
  const [theme, setTheme] = useState<Theme>(Theme.LIGHT);

  // Data State - Starting Empty as requested
  const [chapters, setChapters] = useState<Chapter[]>([]);
  const [activeChapterId, setActiveChapterId] = useState<string | null>(null);
  const [activeConceptId, setActiveConceptId] = useState<string | null>(null);

  // Mock Flashcards storage (in real app, this would be dynamic per chapter)
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);

  // Apply Theme to HTML body
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove('dark', 'reading');
    if (theme === Theme.DARK) html.classList.add('dark');
    if (theme === Theme.READING) html.classList.add('reading');
  }, [theme]);

  // Helpers
  const activeChapter = chapters.find(c => c.id === activeChapterId) || null;
  const activeConcept = activeChapter && activeConceptId 
    ? activeChapter.concepts.find(c => c.id === activeConceptId) 
    : null;

  const handleStartLearning = (conceptId: string) => {
    setActiveConceptId(conceptId);
    setCurrentMode(AppMode.ACTIVE_RECALL);
  };

  const handleRecallComplete = (success: boolean) => {
    if (success) {
      // Logic to update mastery would go here
      setCurrentMode(AppMode.DASHBOARD);
    } else {
        // Logic to create flashcard would go here
        if (activeConcept && activeChapter) {
             const newCard: Flashcard = {
                 id: Date.now().toString(),
                 front: `Explain ${activeConcept.title}`,
                 back: activeConcept.description,
                 mastery: 'AGAIN',
                 nextReviewDate: new Date(),
                 conceptId: activeConcept.id,
                 chapterId: activeChapter.id
             };
             setFlashcards(prev => [...prev, newCard]);
        }
      setCurrentMode(AppMode.FLASHCARDS);
    }
  };

  const handleSelectChapter = (chapter: Chapter) => {
      setActiveChapterId(chapter.id);
      setCurrentMode(AppMode.DASHBOARD);
  };

  const handleCreateChapter = (chapter: Chapter) => {
      setChapters(prev => [...prev, chapter]);
      setActiveChapterId(chapter.id);
      setCurrentMode(AppMode.DASHBOARD);
  };

  const handleGoHome = () => {
      setActiveChapterId(null);
      setCurrentMode(AppMode.SUBJECT_SELECTION);
  };

  const renderContent = () => {
    if (currentMode === AppMode.SUBJECT_SELECTION || !activeChapter) {
        return (
            <SubjectSelection 
                chapters={chapters} 
                onSelectChapter={handleSelectChapter} 
                onChapterCreated={handleCreateChapter} 
            />
        );
    }

    switch (currentMode) {
      case AppMode.DASHBOARD:
        return <ChapterBreakdown chapter={activeChapter} onStartLearning={handleStartLearning} />;
      case AppMode.MIND_MAP:
        return <MindMap chapter={activeChapter} />;
      case AppMode.ACTIVE_RECALL:
        if (!activeConcept) {
             return (
                 <div className="text-center py-20">
                     <p className="text-slate-500 dark:text-slate-400 mb-4">Select a concept from the breakdown to start learning.</p>
                     <button onClick={() => setCurrentMode(AppMode.DASHBOARD)} className="text-primary-600 font-bold hover:underline">Go to Dashboard</button>
                 </div>
             )
        }
        return <ActiveRecall concept={activeConcept} onComplete={handleRecallComplete} />;
      case AppMode.FLASHCARDS:
        // Filter cards for this chapter
        const chapterCards = flashcards.filter(f => f.chapterId === activeChapter.id);
        return <Flashcards cards={chapterCards} />;
      case AppMode.DOUBT_SOLVER:
        return <DoubtSolver />;
      case AppMode.REVISION:
        return <RevisionMode chapter={activeChapter} />;
      case AppMode.ADMIN:
        return <AdminDashboard />;
      default:
        return <ChapterBreakdown chapter={activeChapter} onStartLearning={handleStartLearning} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex font-sans text-slate-900 dark:text-slate-100 transition-colors duration-300">
      <Sidebar 
        currentMode={currentMode} 
        setMode={setCurrentMode} 
        theme={theme}
        setTheme={setTheme}
        onGoHome={handleGoHome}
        activeChapterTitle={activeChapter?.title}
      />

      <main className="flex-1 ml-20 md:ml-64 p-4 md:p-8 overflow-y-auto h-screen scroll-smooth">
        <div className="max-w-7xl mx-auto">
            {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Chapter, Concept } from '../types';
import { Play, CheckCircle2, Circle, Lock } from 'lucide-react';

interface ChapterBreakdownProps {
  chapter: Chapter;
  onStartLearning: (conceptId: string) => void;
}

const ChapterBreakdown: React.FC<ChapterBreakdownProps> = ({ chapter, onStartLearning }) => {
  const totalConcepts = chapter.concepts.length;
  const masteredConcepts = chapter.concepts.filter(c => c.status === 'MASTERED').length;
  const progress = totalConcepts > 0 ? Math.round((masteredConcepts / totalConcepts) * 100) : 0;

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500">
      <header className="space-y-4 mb-10">
        <div className="flex items-center gap-2 text-sm font-medium text-primary-600 dark:text-primary-400 uppercase tracking-wider">
          {chapter.subject}
        </div>
        <h1 className="text-4xl font-serif font-bold text-academic-heading dark:text-white">{chapter.title}</h1>
        <div className="flex items-center gap-4 text-slate-500 dark:text-slate-400 text-sm">
          <span>{totalConcepts} Concepts</span>
          <span>•</span>
          <span>Est. 2-3 Hours</span>
          <span>•</span>
          <span className={`${progress > 75 ? 'text-green-600 dark:text-green-400' : 'text-primary-600 dark:text-primary-400'}`}>{progress}% Complete</span>
        </div>

        <div className="w-full bg-slate-100 dark:bg-slate-800 h-2 rounded-full overflow-hidden mt-4">
          <div 
            className="bg-primary-500 h-full rounded-full transition-all duration-1000 ease-out" 
            style={{ width: `${progress}%` }}
          />
        </div>
      </header>

      <div className="grid gap-4">
        {chapter.concepts.map((concept, index) => (
          <div 
            key={concept.id}
            className={`group relative p-6 rounded-xl border transition-all duration-200
              ${concept.status === 'LOCKED' 
                ? 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800 opacity-60' 
                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-primary-200 dark:hover:border-primary-700 hover:shadow-md'
              }`}
          >
            <div className="flex items-start justify-between gap-4">
              <div className="flex items-start gap-4">
                <div className="mt-1">
                  {concept.status === 'MASTERED' && <CheckCircle2 className="w-6 h-6 text-green-500" />}
                  {concept.status === 'IN_PROGRESS' && <Circle className="w-6 h-6 text-primary-500 fill-primary-50 dark:fill-primary-900/20" />}
                  {concept.status === 'NOT_STARTED' && <Circle className="w-6 h-6 text-slate-300 dark:text-slate-600" />}
                  {concept.status === 'LOCKED' && <Lock className="w-6 h-6 text-slate-300 dark:text-slate-600" />}
                </div>
                <div>
                  <h3 className={`font-semibold text-lg ${concept.status === 'LOCKED' ? 'text-slate-500 dark:text-slate-500' : 'text-slate-800 dark:text-slate-200'}`}>
                    {index + 1}. {concept.title}
                  </h3>
                  <p className="text-slate-500 dark:text-slate-400 text-sm mt-1 leading-relaxed max-w-2xl">
                    {concept.description}
                  </p>
                  {concept.dependencyNote && (
                    <div className="mt-3 flex items-center gap-2 text-xs text-slate-400 dark:text-slate-500">
                      <span className="w-1.5 h-1.5 rounded-full bg-slate-300 dark:bg-slate-600" />
                      {concept.dependencyNote}
                    </div>
                  )}
                </div>
              </div>

              {concept.status !== 'LOCKED' && concept.status !== 'MASTERED' && (
                <button
                  onClick={() => onStartLearning(concept.id)}
                  className="shrink-0 flex items-center gap-2 px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white rounded-lg text-sm font-medium transition-colors"
                >
                  <Play className="w-4 h-4" />
                  {concept.status === 'IN_PROGRESS' ? 'Resume' : 'Start'}
                </button>
              )}
              {concept.status === 'MASTERED' && (
                <button
                   onClick={() => onStartLearning(concept.id)}
                   className="shrink-0 px-4 py-2 text-slate-400 hover:text-primary-600 dark:hover:text-primary-400 text-sm font-medium transition-colors"
                >
                  Review
                </button>
              )}
            </div>

            {/* Connector Line Logic (Visual only for list items) */}
             {index < chapter.concepts.length - 1 && (
               <div className="absolute left-[35px] bottom-0 top-[60px] w-px bg-slate-100 dark:bg-slate-800 -z-10 group-hover:bg-slate-200 dark:group-hover:bg-slate-700 transition-colors" />
             )}
          </div>
        ))}
      </div>
    </div>
  );
};

