import React, { useState, useEffect } from 'react';
import { Concept } from '../types';
import { generateRecallQuestion, evaluateAnswer } from '../services/geminiService';
import { BrainCircuit, Check, X, ArrowRight, Loader2, Sparkles } from 'lucide-react';

interface ActiveRecallProps {
  concept: Concept;
  onComplete: (success: boolean) => void;
}

const ActiveRecall: React.FC<ActiveRecallProps> = ({ concept, onComplete }) => {
  const [question, setQuestion] = useState<string>('');
  const [userAnswer, setUserAnswer] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(true);
  const [evaluating, setEvaluating] = useState<boolean>(false);
  const [feedback, setFeedback] = useState<{ isCorrect: boolean; feedback: string } | null>(null);

  useEffect(() => {
    let mounted = true;
    const loadQuestion = async () => {
      setLoading(true);
      const q = await generateRecallQuestion(concept.title, concept.description);
      if (mounted) {
        setQuestion(q);
        setLoading(false);
      }
    };
    loadQuestion();
    return () => { mounted = false; };
  }, [concept]);

  const handleSubmit = async () => {
    if (!userAnswer.trim()) return;
    setEvaluating(true);
    const result = await evaluateAnswer(question, userAnswer, concept.title);
    setFeedback(result);
    setEvaluating(false);
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400 dark:text-slate-500 animate-pulse">
        <BrainCircuit className="w-16 h-16 mb-4 opacity-50" />
        <p className="font-medium">Generating recall prompt...</p>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto py-8 px-4">
      {/* Concept Header Context */}
      <div className="mb-8 text-center">
        <span className="inline-block px-3 py-1 rounded-full bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-300 text-xs font-bold uppercase tracking-wider mb-2">
          Active Recall
        </span>
        <h2 className="text-2xl font-serif font-bold text-slate-800 dark:text-white">{concept.title}</h2>
      </div>

      {/* Question Card */}
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 p-8 mb-8 relative overflow-hidden transition-colors">
        <div className="absolute top-0 left-0 w-1.5 h-full bg-primary-500"></div>
        <h3 className="text-lg font-medium text-slate-800 dark:text-slate-100 leading-relaxed mb-6">
          {question}
        </h3>

        {!feedback ? (
          <div className="space-y-4">
            <textarea
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              placeholder="Type your explanation here. Don't worry about being perfect, focus on understanding."
              className="w-full h-32 p-4 rounded-xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 focus:bg-white dark:focus:bg-slate-800 focus:border-primary-300 focus:ring-4 focus:ring-primary-50 dark:focus:ring-primary-900/20 transition-all outline-none resize-none text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
            />
            <div className="flex justify-end">
                <button
                onClick={handleSubmit}
                disabled={evaluating || !userAnswer.trim()}
                className="flex items-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-medium transition-all shadow-sm hover:shadow-md"
                >
                {evaluating ? (
                    <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Analyzing...
                    </>
                ) : (
                    <>
                    Submit Answer
                    <ArrowRight className="w-4 h-4" />
                    </>
                )}
                </button>
            </div>
          </div>
        ) : (
          <div className={`mt-6 p-6 rounded-xl border ${feedback.isCorrect ? 'bg-green-50 dark:bg-green-900/20 border-green-100 dark:border-green-800' : 'bg-amber-50 dark:bg-amber-900/20 border-amber-100 dark:border-amber-800'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
            <div className="flex items-start gap-4">
              <div className={`p-2 rounded-full shrink-0 ${feedback.isCorrect ? 'bg-green-100 dark:bg-green-800 text-green-600 dark:text-green-200' : 'bg-amber-100 dark:bg-amber-800 text-amber-600 dark:text-amber-200'}`}>
                {feedback.isCorrect ? <Check className="w-5 h-5" /> : <X className="w-5 h-5" />}
              </div>
              <div>
                <h4 className={`font-bold mb-1 ${feedback.isCorrect ? 'text-green-800 dark:text-green-200' : 'text-amber-800 dark:text-amber-200'}`}>
                  {feedback.isCorrect ? "Excellent Conceptual Grasp" : "Needs Refinement"}
                </h4>
                <p className={`text-sm leading-relaxed ${feedback.isCorrect ? 'text-green-700 dark:text-green-300' : 'text-amber-700 dark:text-amber-300'}`}>
                  {feedback.feedback}
                </p>
              </div>
            </div>

            <div className="mt-6 flex justify-end">
              <button
                onClick={() => onComplete(feedback.isCorrect)}
                className="flex items-center gap-2 px-5 py-2.5 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 hover:border-slate-300 dark:hover:border-slate-500 text-slate-700 dark:text-slate-200 rounded-lg text-sm font-medium shadow-sm transition-all"
              >
                {feedback.isCorrect ? "Continue Learning" : "Review Concept"}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>
          </div>
        )}
      </div>

      <div className="text-center">
         <p className="text-xs text-slate-400 dark:text-slate-500 flex items-center justify-center gap-1">
            <Sparkles className="w-3 h-3" />
            AI evaluates conceptual depth, not keywords.
         </p>
      </div>
    </div>
  );
};

export default ActiveRecall;

import React, { useState } from 'react';
import { Flashcard } from '../types';
import { ThumbsUp, HelpCircle } from 'lucide-react';

interface FlashcardsProps {
  cards: Flashcard[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ cards }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [completed, setCompleted] = useState(false);

  if (!cards || cards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-[50vh] text-slate-500 dark:text-slate-400">
        <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
          <HelpCircle className="w-8 h-8 text-slate-300 dark:text-slate-600" />
        </div>
        <h3 className="text-lg font-medium text-slate-800 dark:text-slate-200">No Cards Due</h3>
        <p className="text-sm">You're all caught up! Check back later.</p>
      </div>
    );
  }

  if (completed) {
     return (
      <div className="flex flex-col items-center justify-center h-[50vh] text-slate-500 dark:text-slate-400 animate-in fade-in zoom-in duration-300">
        <div className="w-16 h-16 bg-green-100 dark:bg-green-900 rounded-full flex items-center justify-center mb-4 text-green-600 dark:text-green-400">
          <ThumbsUp className="w-8 h-8" />
        </div>
        <h3 className="text-xl font-bold text-slate-800 dark:text-slate-200">Session Complete!</h3>
        <p className="text-sm mt-2">You've reviewed {cards.length} cards.</p>
        <button 
          onClick={() => { setCompleted(false); setCurrentIndex(0); }}
          className="mt-6 px-6 py-2 bg-slate-800 dark:bg-slate-700 text-white rounded-lg hover:bg-slate-900 dark:hover:bg-slate-600 transition-colors"
        >
          Review Again
        </button>
      </div>
    );
  }

  const currentCard = cards[currentIndex];

  const handleNext = () => {
    setIsFlipped(false);
    setTimeout(() => {
      if (currentIndex < cards.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        setCompleted(true);
      }
    }, 200);
  };

  return (
    <div className="max-w-xl mx-auto py-12 px-4">
      <div className="flex justify-between items-center mb-6 text-sm text-slate-500 dark:text-slate-400 font-medium">
        <span>Card {currentIndex + 1} of {cards.length}</span>
        <span>Spaced Repetition</span>
      </div>

      <div 
        className="relative h-80 w-full perspective-1000 cursor-pointer group"
        onClick={() => !isFlipped && setIsFlipped(true)}
      >
        <div className={`relative w-full h-full text-center transition-transform duration-500 transform-style-3d shadow-xl rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 ${isFlipped ? 'rotate-y-180' : ''}`}>

          {/* Front */}
          <div className="absolute w-full h-full backface-hidden flex flex-col items-center justify-center p-8">
            <span className="absolute top-6 left-6 text-xs font-bold text-slate-400 dark:text-slate-500 tracking-wider uppercase">Question</span>
            <p className="text-xl font-serif font-medium text-slate-800 dark:text-slate-100 leading-relaxed">
              {currentCard.front}
            </p>
            <p className="absolute bottom-6 text-xs text-slate-400 dark:text-slate-500 animate-pulse">Tap to reveal answer</p>
          </div>

          {/* Back */}
          <div className="absolute w-full h-full backface-hidden rotate-y-180 bg-slate-50 dark:bg-slate-900 flex flex-col items-center justify-center p-8 rounded-2xl">
             <span className="absolute top-6 left-6 text-xs font-bold text-primary-600 dark:text-primary-400 tracking-wider uppercase">Answer</span>
             <p className="text-lg text-slate-700 dark:text-slate-300 leading-relaxed">
              {currentCard.back}
            </p>
          </div>
        </div>
      </div>

      {isFlipped && (
        <div className="mt-8 grid grid-cols-3 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-300">
          <button 
            onClick={handleNext}
            className="flex flex-col items-center gap-2 p-4 rounded-xl bg-amber-50 dark:bg-amber-900/20 hover:bg-amber-100 dark:hover:bg-amber-900/30 text-amber-700 dark:text-amber-400 border border-amber-100 dark:border-amber-800 transition-all"
          >
            <span className="text-lg font-bold">Hard</span>
            <span className="text-xs opacity-75">Review soon</span>
          </button>
          <button 
             onClick={handleNext}
             className="flex flex-col items-center gap-2 p-4 rounded-xl bg-blue-50 dark:bg-blue-900/20 hover:bg-blue-100 dark:hover:bg-blue-900/30 text-blue-700 dark:text-blue-400 border border-blue-100 dark:border-blue-800 transition-all"
          >
            <span className="text-lg font-bold">Good</span>
            <span className="text-xs opacity-75">Review later</span>
          </button>
          <button 
             onClick={handleNext}
             className="flex flex-col items-center gap-2 p-4 rounded-xl bg-green-50 dark:bg-green-900/20 hover:bg-green-100 dark:hover:bg-green-900/30 text-green-700 dark:text-green-400 border border-green-100 dark:border-green-800 transition-all"
          >
            <span className="text-lg font-bold">Easy</span>
            <span className="text-xs opacity-75">Review in 4d</span>
          </button>
        </div>
      )}

      {/* Helper styles for 3d flip card */}
      <style>{`
        .perspective-1000 { perspective: 1000px; }
        .transform-style-3d { transform-style: preserve-3d; }
        .backface-hidden { backface-visibility: hidden; }
        .rotate-y-180 { transform: rotateY(180deg); }
      `}</style>
    </div>
  );
};

export default Flashcards;

import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { getDoubtResponse } from '../services/geminiService';
import { Send, User, Bot, Loader2 } from 'lucide-react';

const DoubtSolver: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'model', content: "Hello! I'm your AI tutor. I can help clarify any concept from this chapter. What's confusing you?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Simulate context awareness
    const context = "Current Chapter Context"; 

    // Get AI response
    const responseText = await getDoubtResponse([...messages, userMsg], context);

    const botMsg: Message = { id: (Date.now() + 1).toString(), role: 'model', content: responseText, timestamp: Date.now() };

    setMessages(prev => [...prev, botMsg]);
    setIsTyping(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-4rem)] max-w-3xl mx-auto bg-white dark:bg-slate-900 border-x border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
      <div className="p-4 border-b border-slate-100 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md sticky top-0 z-10">
        <h2 className="font-serif font-bold text-slate-800 dark:text-slate-100">Doubt Solver</h2>
        <p className="text-xs text-slate-500 dark:text-slate-400">Context aware</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex items-start gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${msg.role === 'user' ? 'bg-slate-200 dark:bg-slate-700' : 'bg-primary-100 dark:bg-primary-900 text-primary-600 dark:text-primary-400'}`}>
              {msg.role === 'user' ? <User className="w-4 h-4 text-slate-500 dark:text-slate-300" /> : <Bot className="w-5 h-5" />}
            </div>
            <div 
              className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed
              ${msg.role === 'user' 
                ? 'bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-tr-none' 
                : 'bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 text-slate-700 dark:text-slate-300 shadow-sm rounded-tl-none'}`}
            >
              {msg.content}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex items-center gap-2 text-slate-400 text-xs ml-12">
            <Loader2 className="w-3 h-3 animate-spin" />
            Thinking...
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 border-t border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900">
        <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-800 p-2 rounded-xl border border-slate-200 dark:border-slate-700 focus-within:border-primary-300 focus-within:ring-4 focus-within:ring-primary-50 dark:focus-within:ring-primary-900/20 transition-all">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask a question..."
            className="flex-1 bg-transparent border-none outline-none text-slate-800 dark:text-slate-100 placeholder:text-slate-400 px-2"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-2 bg-primary-600 hover:bg-primary-700 disabled:opacity-50 text-white rounded-lg transition-colors"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default DoubtSolver;

import React, { useState } from 'react';
import { Chapter } from '../types';
import { CheckSquare, Square, ArrowRight, Award } from 'lucide-react';

interface RevisionModeProps {
  chapter: Chapter;
}

const RevisionMode: React.FC<RevisionModeProps> = ({ chapter }) => {
  const [checkedConcepts, setCheckedConcepts] = useState<Set<string>>(new Set());
  const [stage, setStage] = useState<'CHECKLIST' | 'SCAN' | 'DONE'>('CHECKLIST');

  const toggleCheck = (id: string) => {
    const next = new Set(checkedConcepts);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setCheckedConcepts(next);
  };

  if (stage === 'DONE') {
