import React, { useState } from 'react';
import { Chapter } from '../types';
import { generateChapter } from '../services/geminiService';
import { BookOpen, ArrowRight, Atom, Calculator, Sparkles, Plus, Loader2 } from 'lucide-react';

interface SubjectSelectionProps {
  chapters: Chapter[];
  onSelectChapter: (chapter: Chapter) => void;
  onChapterCreated: (chapter: Chapter) => void;
}

const SubjectSelection: React.FC<SubjectSelectionProps> = ({ chapters, onSelectChapter, onChapterCreated }) => {
  const [selectedSubject, setSelectedSubject] = useState<string>('All');
  const [customTopic, setCustomTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const subjects = ['All', ...Array.from(new Set(chapters.map(c => c.subject)))];

  const filteredChapters = selectedSubject === 'All' 
    ? chapters 
    : chapters.filter(c => c.subject === selectedSubject);

  const handleGenerate = async () => {
    if (!customTopic.trim()) return;
    setIsGenerating(true);
    const newChapter = await generateChapter(customTopic, '8th Grade');
    if (newChapter) {
      onChapterCreated(newChapter);
    }
    setIsGenerating(false);
  };

  const getSubjectIcon = (subject: string) => {
    switch (subject) {
      case 'Maths': return <Calculator className="w-5 h-5" />;
      case 'Science': return <Atom className="w-5 h-5" />;
      default: return <BookOpen className="w-5 h-5" />;
    }
  };

  return (
    <div className="max-w-6xl mx-auto py-4 md:py-12 space-y-8 md:space-y-12 animate-in fade-in duration-500">

      {/* Hero Section */}
      <div className="text-center space-y-4 px-4">
        <h1 className="text-3xl md:text-5xl font-serif font-bold text-slate-900 dark:text-white leading-tight">
          What do you want to <span className="text-primary-600 dark:text-primary-400">master</span> today?
        </h1>
        <p className="text-base md:text-lg text-slate-600 dark:text-slate-400 max-w-2xl mx-auto">
          Select a chapter from your NCERT syllabus or ask AI to create a custom learning path for any topic.
        </p>
      </div>

      {/* AI Generator Card */}
      <div className="mx-4">
        <div className="max-w-2xl mx-auto bg-gradient-to-br from-primary-600 to-primary-800 rounded-2xl p-6 md:p-8 shadow-xl text-white">
          <div className="flex items-center gap-2 mb-4 opacity-90">
            <Sparkles className="w-5 h-5" />
            <span className="font-bold uppercase tracking-wider text-xs md:text-sm">AI Curriculum Generator</span>
          </div>
          <h3 className="text-xl md:text-2xl font-bold mb-2">Study Anything.</h3>
          <p className="text-primary-100 mb-6 text-sm md:text-base">Not in the list? Generate a structured chapter instantly.</p>

          <div className="flex flex-col sm:flex-row gap-2 md:gap-3 bg-white/10 p-2 rounded-xl border border-white/20 backdrop-blur-sm">
            <input 
              type="text" 
              value={customTopic}
              onChange={(e) => setCustomTopic(e.target.value)}
              placeholder="e.g. Black Holes, Algebra, French Revolution..."
              className="flex-1 bg-transparent border-none outline-none text-white placeholder:text-primary-200 px-2 py-2 text-base md:text-lg w-full"
              onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
            />
            <button 
              onClick={handleGenerate}
              disabled={isGenerating || !customTopic.trim()}
              className="w-full sm:w-auto px-6 py-3 bg-white text-primary-700 font-bold rounded-lg hover:bg-primary-50 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
            >
              {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Plus className="w-5 h-5" />}
              <span>Generate</span>
            </button>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap justify-center gap-2 md:gap-4 px-4">
        {subjects.map(subject => (
          <button
            key={subject}
            onClick={() => setSelectedSubject(subject)}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 border
              ${selectedSubject === subject 
                ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 border-slate-900 dark:border-white shadow-lg transform scale-105' 
                : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600 hover:shadow-sm'
              }`}
          >
            {subject}
          </button>
        ))}
      </div>

      {/* Chapter Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 px-4 pb-8">
        {filteredChapters.map(chapter => (
          <div 
            key={chapter.id}
            onClick={() => onSelectChapter(chapter)}
            className="group bg-white dark:bg-slate-800 rounded-xl p-6 border border-slate-200 dark:border-slate-700 hover:border-primary-300 dark:hover:border-primary-600 hover:shadow-lg transition-all duration-300 cursor-pointer flex flex-col h-full"
          >
            <div className="flex items-start justify-between mb-4">
              <div className={`p-3 rounded-lg ${chapter.subject === 'Maths' ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-600' : 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600'}`}>
                {getSubjectIcon(chapter.subject)}
              </div>
              <span className="text-xs font-bold text-slate-400 dark:text-slate-500 bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded">
                {chapter.concepts.length} Concepts
              </span>
            </div>

            <h3 className="text-xl font-serif font-bold text-slate-800 dark:text-slate-100 mb-2 group-hover:text-primary-600 dark:group-hover:text-primary-400 transition-colors line-clamp-2">
              {chapter.title}
            </h3>

            <p className="text-sm text-slate-500 dark:text-slate-400 line-clamp-2 mb-6 flex-1">
              {chapter.concepts[0]?.description || "Start your journey in this topic."}
            </p>

            <div className="flex items-center text-primary-600 dark:text-primary-400 font-medium text-sm mt-auto group-hover:translate-x-1 transition-transform">
              Start Learning
              <ArrowRight className="w-4 h-4 ml-1" />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

