  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // Interaction State
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  // --- Layout Algorithm ---
  useEffect(() => {
    // 1. Convert Linear Data to Tree Structure
    const rootNode: TreeNode = {
      id: 'root',
      data: { title: chapter.title, isRoot: true },
      x: 0,
      y: 0,
      width: 260, // Root is wider
      height: 90,
      children: []
    };

    const conceptMap = new Map<string, TreeNode>();

    // Create nodes for all concepts
    chapter.concepts.forEach(c => {
      conceptMap.set(c.id, {
        id: c.id,
        data: c,
        x: 0, 
        y: 0,
        width: NODE_WIDTH,
        height: NODE_HEIGHT,
        children: []
      });
    });

    // Build hierarchy based on prerequisites
    // Simulating a tree: if B depends on A, B is child of A.
    // If no prereqs, it's child of Root.
    const orphans: TreeNode[] = [];

    chapter.concepts.forEach(c => {
      const node = conceptMap.get(c.id)!;
      if (c.prerequisites && c.prerequisites.length > 0) {
        // Find the "closest" parent (using the last prereq as immediate parent for visual tree)
        const parentId = c.prerequisites[c.prerequisites.length - 1];
        const parent = conceptMap.get(parentId);
        if (parent) {
          parent.children.push(node);
          node.parentId = parentId;
        } else {
          orphans.push(node);
        }
      } else {
        orphans.push(node);
      }
    });

    rootNode.children = orphans;

    // 2. Recursive Position Calculation
    // Calculate subtree width to center parents
    const calculateSubtreeWidth = (node: TreeNode): number => {
      if (node.children.length === 0) return node.width;
      const childrenWidth = node.children.reduce((acc, child) => acc + calculateSubtreeWidth(child), 0);
      const gaps = (node.children.length - 1) * HORIZONTAL_GAP;
      return Math.max(node.width, childrenWidth + gaps);
    };

    const assignPositions = (node: TreeNode, x: number, y: number) => {
      node.x = x;
      node.y = y;

      if (node.children.length > 0) {
        const subtreeWidths = node.children.map(calculateSubtreeWidth);
        const totalChildrenWidth = subtreeWidths.reduce((a, b) => a + b, 0) + (node.children.length - 1) * HORIZONTAL_GAP;

        let currentX = x - totalChildrenWidth / 2;

        node.children.forEach((child, i) => {
          const childSubtreeWidth = subtreeWidths[i];
          // Center the child within its allocated subtree width
          const childX = currentX + childSubtreeWidth / 2;
          assignPositions(child, childX, y + VERTICAL_GAP);
          currentX += childSubtreeWidth + HORIZONTAL_GAP;
        });
      }
    };

    calculateSubtreeWidth(rootNode);
    assignPositions(rootNode, 0, 0);

    // 3. Flatten for Rendering
    const flattenedNodes: TreeNode[] = [];
    const flattenedEdges: { x1: number, y1: number, x2: number, y2: number }[] = [];

    const traverse = (node: TreeNode) => {
      flattenedNodes.push(node);
      node.children.forEach(child => {
        flattenedEdges.push({
          x1: node.x,
          y1: node.y + node.height / 2,
          x2: child.x,
          y2: child.y - child.height / 2
        });
        traverse(child);
      });
    };

    traverse(rootNode);
    setNodes(flattenedNodes);
    setEdges(flattenedEdges);

    // Center initially
    if (containerRef.current) {
        setPosition({ x: containerRef.current.clientWidth / 2, y: 100 });
    }

  }, [chapter]);


  // --- Event Handlers ---

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault(); // Stop page scroll if possible, though React synthetic events might be late.
    // Simple zoom
    const newScale = Math.min(Math.max(0.2, scale - e.deltaY * 0.001), 2);
    setScale(newScale);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    // Only drag if clicking background
    if ((e.target as HTMLElement).closest('.mindmap-node')) return;
    setIsDragging(true);
    setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      setPosition({
        x: e.clientX - dragStart.x,
        y: e.clientY - dragStart.y
      });
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  return (
    <div className="relative h-[calc(100vh-6rem)] w-full overflow-hidden bg-slate-50 dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 shadow-inner select-none">

      {/* Controls */}
      <div className="absolute top-4 right-4 z-20 flex flex-col gap-2 bg-white dark:bg-slate-800 p-2 rounded-lg shadow-md border border-slate-100 dark:border-slate-700">
        <button onClick={() => setScale(s => Math.min(s + 0.2, 2))} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300">
          <ZoomIn className="w-5 h-5" />
        </button>
        <button onClick={() => setScale(s => Math.max(s - 0.2, 0.2))} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300">
          <ZoomOut className="w-5 h-5" />
        </button>
        <button onClick={() => { setScale(0.8); setPosition({ x: containerRef.current ? containerRef.current.clientWidth/2 : 0, y: 100 }); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300">
          <Maximize2 className="w-5 h-5" />
        </button>
        <div className="h-px bg-slate-200 dark:bg-slate-700 my-1" />
        <div className="p-2 flex justify-center text-slate-400">
            <Move className="w-5 h-5" />
        </div>
      </div>

      <div className="absolute top-4 left-4 z-20 bg-white/80 dark:bg-slate-900/80 backdrop-blur p-3 rounded-lg border border-slate-200 dark:border-slate-700">
        <h2 className="font-serif font-bold text-slate-800 dark:text-slate-100">Interactive Mind Map</h2>
        <p className="text-xs text-slate-500 dark:text-slate-400">Scroll to zoom • Drag to move • Click to expand</p>
      </div>

      {/* Canvas */}
      <div 
        ref={containerRef}
        className={`w-full h-full cursor-grab ${isDragging ? 'cursor-grabbing' : ''}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onWheel={handleWheel}
      >
        <div 
          style={{ 
            transform: `translate(${position.x}px, ${position.y}px) scale(${scale})`,
            transformOrigin: '0 0',
            transition: isDragging ? 'none' : 'transform 0.1s ease-out'
          }}
          className="w-full h-full"
        >
          {/* Edges Layer (SVG) */}
          <svg className="absolute top-0 left-0 overflow-visible pointer-events-none" style={{ width: 1, height: 1 }}>
            {edges.map((edge, i) => (
              <path
                key={i}
                d={`M ${edge.x1} ${edge.y1} C ${edge.x1} ${edge.y1 + VERTICAL_GAP/2}, ${edge.x2} ${edge.y2 - VERTICAL_GAP/2}, ${edge.x2} ${edge.y2}`}
                fill="none"
                stroke="#cbd5e1" // slate-300
                strokeWidth="2"
                className="dark:stroke-slate-600"
              />
            ))}
          </svg>

          {/* Nodes Layer (HTML) */}
          {nodes.map(node => {
             const isRoot = (node.data as any).isRoot;
             const isSelected = selectedNodeId === node.id;
             const concept = node.data as Concept;

             return (
              <div
                key={node.id}
                onClick={(e) => { e.stopPropagation(); setSelectedNodeId(isSelected ? null : node.id); }}
                className={`
                  mindmap-node absolute flex flex-col items-center justify-center p-4 rounded-2xl shadow-sm border-2 transition-all duration-300 hover:scale-105 cursor-pointer
                  ${isRoot 
                    ? 'bg-primary-600 border-primary-700 text-white shadow-xl z-10' 
                    : isSelected
                      ? 'bg-white dark:bg-slate-800 border-primary-500 ring-4 ring-primary-100 dark:ring-primary-900/40 z-20'
                      : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-primary-300 dark:hover:border-primary-600'
                  }
                `}
                style={{
                  left: node.x,
                  top: node.y,
                  width: node.width,
                  height: isSelected && !isRoot ? 'auto' : node.height,
                  minHeight: node.height,
                  marginLeft: -node.width / 2, // Centering
                  marginTop: -node.height / 2, // Centering
                }}
              >
                <div className={`text-center transition-all ${isRoot ? '' : ''}`}>
                    <h3 className={`font-serif font-bold leading-tight ${isRoot ? 'text-lg' : 'text-sm text-slate-800 dark:text-slate-100'}`}>
                        {isRoot ? (node.data as any).title : concept.title}
                    </h3>

                    {/* Collapsed View for non-root */}
                    {!isRoot && !isSelected && (
                        <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-wider font-medium">Click to view</p>
                    )}

                    {/* Expanded View */}
                    {!isRoot && isSelected && (
                        <div className="mt-3 text-xs text-slate-600 dark:text-slate-300 border-t border-slate-100 dark:border-slate-700 pt-2 animate-in fade-in slide-in-from-top-1 duration-200">
                            <p className="leading-relaxed">{concept.description}</p>
                            {concept.dependencyNote && (
                                <div className="mt-2 text-[10px] text-primary-600 dark:text-primary-400 bg-primary-50 dark:bg-primary-900/20 py-1 px-2 rounded-full inline-block">
                                   Note: {concept.dependencyNote}
                                </div>
                            )}
                        </div>
                    )}
                </div>
              </div>
            );
          })}

        </div>
      </div>
    </div>
  );
};

export default MindMap;

