export const getDoubtResponse = async (history: Message[], currentContext: string): Promise<string> => {
  if (!ai) initGemini();
  if (!ai) return "I am ready to help, but the AI service is currently unavailable.";

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        systemInstruction: `You are an expert Tutor for 8th grade students.
        The student is studying: ${currentContext}.

        Instructions:
        1. Answer doubts with extreme clarity and simplicity.
        2. Use analogies suitable for a 13-14 year old.
        3. ${LATEX_INSTRUCTION}
        4. Be concise but complete.
        5. Use **bold** for important terms.`,
      },
    });

    const lastUserMessage = history[history.length - 1];

    const result = await chat.sendMessage({
      message: lastUserMessage.content
    });

    return result.text || "I'm not sure how to answer that right now.";

  } catch (error) {
    console.error("Doubt Solver Error:", error);
    return "I encountered an error trying to process your doubt.";
  }
};

import React, { useRef, useState, useEffect } from 'react';
import { Chapter, Concept } from '../types';
import { ZoomIn, ZoomOut, Move, Maximize2, Settings2, Sparkles, Layers, BrainCircuit, Check, Loader2 } from 'lucide-react';
import { generateMindMapData } from '../services/geminiService';

interface MindMapProps {
  chapter: Chapter;
}

interface TreeNode {
  id: string;
  data: { title: string; description: string; isRoot: boolean; [key: string]: any };
  x: number;
  y: number;
  width: number;
  height: number;
  children: TreeNode[];
  parentId?: string;
  depth: number;
}

// Configuration Types
type Complexity = 'BASIC' | 'INTERMEDIATE' | 'ADVANCED';
type DetailLevel = 'BRIEF' | 'STANDARD' | 'DETAILED';

const NODE_WIDTH = 240; // Increased width
const NODE_HEIGHT = 80;
const VERTICAL_GAP = 140; // Increased gap
const HORIZONTAL_GAP = 60; // Increased gap

const MindMap: React.FC<MindMapProps> = ({ chapter }) => {
  // Config State
  const [config, setConfig] = useState<{ complexity: Complexity; detail: DetailLevel } | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [generatedMapData, setGeneratedMapData] = useState<{ rootTitle: string; nodes: any[] } | null>(null);

  // Map State
  const containerRef = useRef<HTMLDivElement>(null);
  const [nodes, setNodes] = useState<TreeNode[]>([]);
  const [edges, setEdges] = useState<{ x1: number, y1: number, x2: number, y2: number }[]>([]);

  // Viewport State
  const [scale, setScale] = useState(0.8);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // Interaction State
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  // --- Generate Handler ---
  const handleGenerate = async () => {
    if (!config) return;
    setIsLoading(true);
    const data = await generateMindMapData(chapter.title, config.complexity, config.detail);
    if (data) {
        setGeneratedMapData(data);
    }
    setIsLoading(false);
  };

  // --- Layout Algorithm ---
  useEffect(() => {
    if (!generatedMapData) return;

    // 1. Convert Data to Tree Structure
    const rootNode: TreeNode = {
      id: 'root',
      data: { title: generatedMapData.rootTitle, description: "Main Topic", isRoot: true },
      x: 0,
      y: 0,
      width: 280, 
      height: 90,
      children: [],
      depth: 0
    };

    const nodeMap = new Map<string, TreeNode>();

    // Create nodes
    generatedMapData.nodes.forEach(n => {
      nodeMap.set(n.id, {
        id: n.id,
        data: { ...n, isRoot: false },
        x: 0, 
        y: 0,
        width: NODE_WIDTH,
        height: NODE_HEIGHT,
        children: [],
        depth: 0
      });
    });

    // Build hierarchy
    const orphans: TreeNode[] = [];

    generatedMapData.nodes.forEach(n => {
      const node = nodeMap.get(n.id)!;
      // Handle parent mapping (AI returns 'root' or a node ID)
      const pid = n.parentId;

      if (!pid || pid === 'root') {
          rootNode.children.push(node);
          node.parentId = 'root';
      } else {
          const parent = nodeMap.get(pid);
          if (parent) {
              parent.children.push(node);
              node.parentId = pid;
          } else {
              // Fallback if parent not found, attach to root
              rootNode.children.push(node);
              node.parentId = 'root';
          }
      }
    });

    // 2. Recursive Position Calculation (Same algorithm as before)
    const calculateSubtreeWidth = (node: TreeNode, depth: number): number => {
      node.depth = depth;
      if (node.children.length === 0) return node.width;
      const childrenWidth = node.children.reduce((acc, child) => acc + calculateSubtreeWidth(child, depth + 1), 0);
      const gaps = (node.children.length - 1) * HORIZONTAL_GAP;
      return Math.max(node.width, childrenWidth + gaps);
    };

    const assignPositions = (node: TreeNode, x: number, y: number) => {
      node.x = x;
      node.y = y;

      if (node.children.length > 0) {
        // Recalculate widths locally for placement
        const getStoredWidth = (n: TreeNode) => {
            if (n.children.length === 0) return n.width;
            const w = n.children.reduce((acc, c) => acc + getStoredWidth(c), 0) + (n.children.length - 1) * HORIZONTAL_GAP;
            return Math.max(n.width, w);
        };

        const childWidths = node.children.map(getStoredWidth);
        const totalChildrenWidth = childWidths.reduce((a, b) => a + b, 0) + (node.children.length - 1) * HORIZONTAL_GAP;

        let currentX = x - totalChildrenWidth / 2;

        node.children.forEach((child, i) => {
          const w = childWidths[i];
          const childX = currentX + w / 2;
          assignPositions(child, childX, y + VERTICAL_GAP);
          currentX += w + HORIZONTAL_GAP;
        });
      }
    };

    calculateSubtreeWidth(rootNode, 0);
    assignPositions(rootNode, 0, 0);

    // 3. Flatten for Rendering
    const flattenedNodes: TreeNode[] = [];
    const flattenedEdges: { x1: number, y1: number, x2: number, y2: number }[] = [];

    const traverse = (node: TreeNode) => {
      flattenedNodes.push(node);
      node.children.forEach(child => {
        flattenedEdges.push({
          x1: node.x,
          y1: node.y + node.height / 2,
          x2: child.x,
          y2: child.y - child.height / 2
        });
        traverse(child);
      });
    };

    traverse(rootNode);
    setNodes(flattenedNodes);
    setEdges(flattenedEdges);

    // Center initially
    if (containerRef.current) {
        setPosition({ x: containerRef.current.clientWidth / 2, y: 100 });
    }

  }, [generatedMapData]);


  // --- Event Handlers ---

  const handleWheel = (e: React.WheelEvent) => {
    if(e.ctrlKey || e.metaKey) {
        e.preventDefault(); 
        const newScale = Math.min(Math.max(0.2, scale - e.deltaY * 0.001), 2);
        setScale(newScale);
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('.mindmap-node')) return;
    setIsDragging(true);
    setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      setPosition({
        x: e.clientX - dragStart.x,
        y: e.clientY - dragStart.y
      });
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  // --- Configuration Screen Render ---
  if (!config || !generatedMapData) {
    return (
      <div className="max-w-4xl mx-auto py-12 px-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="text-center mb-12">
          <h2 className="text-3xl font-serif font-bold text-slate-800 dark:text-white mb-4">
             Generate Mind Map
          </h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-lg mx-auto">
             Customize how you want to visualize the connections in this chapter.
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-8 mb-12">
           {/* Detail Level */}
           <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
              <div className="flex items-center gap-3 mb-6">
                 <div className="p-2 bg-blue-50 dark:bg-blue-900/20 text-blue-600 rounded-lg">
                    <Layers className="w-6 h-6" />
                 </div>
                 <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Detail Level</h3>
              </div>
              <div className="space-y-3">
                 {(['BRIEF', 'STANDARD', 'DETAILED'] as DetailLevel[]).map(level => (
                    <button
                        key={level}
                        onClick={() => setConfig(prev => ({ complexity: prev?.complexity || 'INTERMEDIATE', detail: level }))}
                        className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all group
                        ${config?.detail === level 
                            ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20 ring-1 ring-blue-500' 
                            : 'border-slate-200 dark:border-slate-700 hover:border-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/10'}`}
                    >
                        <span className="font-medium text-slate-700 dark:text-slate-300 capitalize">{level.toLowerCase()}</span>
                        {config?.detail === level && <Check className="w-5 h-5 text-blue-600 dark:text-blue-400" />}
                    </button>
                 ))}
              </div>
           </div>

           {/* Complexity */}
           <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
              <div className="flex items-center gap-3 mb-6">
                 <div className="p-2 bg-purple-50 dark:bg-purple-900/20 text-purple-600 rounded-lg">
                    <BrainCircuit className="w-6 h-6" />
                 </div>
                 <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Complexity</h3>
              </div>
              <div className="space-y-3">
                 {(['BASIC', 'INTERMEDIATE', 'ADVANCED'] as Complexity[]).map(comp => (
                    <button
                        key={comp}
                        onClick={() => setConfig(prev => ({ detail: prev?.detail || 'STANDARD', complexity: comp }))}
                        className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all group
                        ${config?.complexity === comp 
                            ? 'border-purple-500 bg-purple-50 dark:bg-purple-900/20 ring-1 ring-purple-500' 
                            : 'border-slate-200 dark:border-slate-700 hover:border-purple-500 hover:bg-purple-50 dark:hover:bg-purple-900/10'}`}
                    >
                         <span className="font-medium text-slate-700 dark:text-slate-300 capitalize">{comp.toLowerCase()}</span>
                         {config?.complexity === comp && <Check className="w-5 h-5 text-purple-600 dark:text-purple-400" />}
                    </button>
                 ))}
              </div>
           </div>
        </div>

        <div className="flex justify-center">
            <button 
                onClick={handleGenerate}
                disabled={!config || isLoading}
                className={`flex items-center gap-2 px-8 py-4 bg-primary-600 hover:bg-primary-700 text-white rounded-xl font-bold text-lg shadow-lg hover:shadow-xl hover:scale-105 transition-all
                ${(!config || isLoading) ? 'opacity-50 cursor-not-allowed transform-none' : ''}`}
            >
                {isLoading ? (
                    <>
                    <Loader2 className="w-5 h-5 animate-spin" />
                    Generating Structure...
                    </>
                ) : (
                    <>
                    <Sparkles className="w-5 h-5" />
                    Generate Map
                    </>
                )}
            </button>
        </div>
      </div>
    );
  }

  return (
    <div className="relative h-[calc(100vh-6rem)] w-full overflow-hidden bg-slate-50 dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 shadow-inner select-none animate-in fade-in duration-700">

      {/* Controls */}
      <div className="absolute top-4 right-4 z-30 flex flex-col gap-2 bg-white dark:bg-slate-800 p-2 rounded-lg shadow-md border border-slate-100 dark:border-slate-700">
        <button onClick={() => setScale(s => Math.min(s + 0.2, 2))} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300" title="Zoom In">
          <ZoomIn className="w-5 h-5" />
        </button>
        <button onClick={() => setScale(s => Math.max(s - 0.2, 0.2))} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300" title="Zoom Out">
          <ZoomOut className="w-5 h-5" />
        </button>
        <button onClick={() => { setScale(0.8); setPosition({ x: containerRef.current ? containerRef.current.clientWidth/2 : 0, y: 100 }); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300" title="Fit View">
          <Maximize2 className="w-5 h-5" />
        </button>
        <div className="h-px bg-slate-200 dark:bg-slate-700 my-1" />
        <button 
            onClick={() => { setConfig(null); setGeneratedMapData(null); }} 
            className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded text-slate-600 dark:text-slate-300" 
            title="Reconfigure"
        >
            <Settings2 className="w-5 h-5" />
        </button>
      </div>

      <div className="absolute top-4 left-4 z-30 bg-white/90 dark:bg-slate-900/90 backdrop-blur p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
        <h2 className="font-serif font-bold text-slate-800 dark:text-slate-100">{chapter.title}</h2>
        <div className="flex items-center gap-3 mt-1 text-xs text-slate-500 dark:text-slate-400">
            <span className="flex items-center gap-1"><Layers className="w-3 h-3"/> {config.detail}</span>
            <span className="flex items-center gap-1"><BrainCircuit className="w-3 h-3"/> {config.complexity}</span>
        </div>
      </div>

      {/* Canvas */}
      <div 
        ref={containerRef}
        className={`w-full h-full cursor-grab ${isDragging ? 'cursor-grabbing' : ''}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onWheel={handleWheel}
      >
        <div 
          style={{ 
            transform: `translate(${position.x}px, ${position.y}px) scale(${scale})`,
            transformOrigin: '0 0',
            transition: isDragging ? 'none' : 'transform 0.1s ease-out'
          }}
          className="w-full h-full"
        >
          {/* Edges Layer (SVG) */}
          <svg className="absolute top-0 left-0 overflow-visible pointer-events-none" style={{ width: 1, height: 1 }}>
            {edges.map((edge, i) => (
              <path
                key={i}
                d={`M ${edge.x1} ${edge.y1} C ${edge.x1} ${edge.y1 + VERTICAL_GAP * 0.5}, ${edge.x2} ${edge.y2 - VERTICAL_GAP * 0.5}, ${edge.x2} ${edge.y2}`}
                fill="none"
                stroke="#cbd5e1" // slate-300
                strokeWidth="2"
                className="dark:stroke-slate-700 animate-in fade-in duration-1000"
                style={{ animationDelay: `${i * 100}ms` }}
              />
            ))}
          </svg>

          {/* Nodes Layer (HTML) */}
          {nodes.map((node, index) => {
             const isRoot = node.data.isRoot;
             const isSelected = selectedNodeId === node.id;
             const concept = node.data;

             // Staggered animation delay based on depth/index
             const animationDelay = `${index * 150}ms`;

             return (
              <div
                key={node.id}
                onClick={(e) => { e.stopPropagation(); setSelectedNodeId(isSelected ? null : node.id); }}
                className={`
                  mindmap-node absolute flex flex-col items-center justify-center rounded-2xl shadow-sm border-2 cursor-pointer
                  transition-all duration-500 ease-in-out
                  animate-in zoom-in-50 fade-in fill-mode-backwards
                  ${isRoot 
                    ? 'bg-primary-600 border-primary-700 text-white shadow-xl z-20' 
                    : isSelected
                      ? 'bg-white dark:bg-slate-800 border-primary-500 ring-4 ring-primary-100 dark:ring-primary-900/40 z-50 shadow-2xl scale-110'
                      : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-primary-300 dark:hover:border-primary-600 hover:scale-105 z-10'
                  }
                `}
                style={{
                  left: node.x,
                  top: node.y,
                  width: node.width,
                  // Smoothly animate height when expanding
                  height: isSelected && !isRoot ? 'auto' : node.height,
                  minHeight: node.height,
                  marginLeft: -node.width / 2, // Centering
                  marginTop: -node.height / 2, // Centering
                  animationDelay: animationDelay,
                  padding: isSelected ? '1.5rem' : '1rem'
                }}
              >
                <div className="w-full h-full flex flex-col items-center justify-center">
                    <h3 className={`font-serif font-bold leading-tight text-center w-full ${isRoot ? 'text-lg' : 'text-sm text-slate-800 dark:text-slate-100'}`}>
                        {concept.title}
                    </h3>

                    {/* Collapsed View for non-root */}
                    {!isRoot && !isSelected && (
                        <div className="mt-2 w-8 h-1 bg-slate-100 dark:bg-slate-700 rounded-full group-hover:bg-primary-100 transition-colors" />
                    )}

                    {/* Expanded View with Animation */}
                    <div 
                        className={`
                            overflow-hidden transition-all duration-500 ease-in-out w-full
                            ${!isRoot && isSelected ? 'max-h-[300px] opacity-100 mt-3 pt-3 border-t border-slate-100 dark:border-slate-700' : 'max-h-0 opacity-0'}
                        `}
                    >
                         {!isRoot && (
                            <div className="text-xs text-slate-600 dark:text-slate-300 text-left">
                                <p className="leading-relaxed mb-3">{concept.description}</p>

                                {concept.type && (
                                  <div className="inline-block px-2 py-1 rounded bg-slate-100 dark:bg-slate-700 text-[10px] font-bold uppercase tracking-wider mb-2">
                                    {concept.type}
                                  </div>
                                )}
                            </div>
                         )}
                    </div>
                </div>
              </div>
            );
          })}

        </div>
      </div>
    </div>
  );
};

